#!/usr/bin/env php
<?php

declare(strict_types=1);

/**
 * Generic Nour entry point.
 *
 * Two autoloaders are layered:
 *
 *   1. The framework's autoload (`Nour\…`), bundled in the image at
 *      `/opt/nour/vendor/autoload.php`.
 *   2. The host app's autoload (`App\…`, `Timers\…`), generated by
 *      `composer install` in the project directory and resolved from
 *      `$NOUR_APP_DIR/vendor/autoload.php`.
 *
 * Both are PSR-4 autoloaders registered via `spl_autoload_register`,
 * so they coexist without overriding each other — `Nour\` resolves
 * from the image, `App\` from the mounted project.
 *
 * Usage in a Docker image:
 *
 *     ENV NOUR_APP_DIR=/app
 *     ENTRYPOINT ["php", "/opt/nour/bin/server.php"]
 *
 * Standalone (running the framework without an image):
 *
 *     NOUR_APP_DIR=$(pwd) php /path/to/nour/bin/server.php
 *
 * Either way, the project must contain:
 *   - `data/setup.json`     — server topology
 *   - `data/sitting.json`   — runtime config (DB, Redis, …)
 *   - `lib/app/Bootstrap.php` (or wherever `setup.json:bootstrap` points)
 *   - a composer-generated `vendor/autoload.php` for the App namespace
 */

$appDir = getenv('NOUR_APP_DIR') ?: getcwd();
$appDir = rtrim((string) $appDir, "/\\");

// 1. Framework autoload (always required). When running standalone this
//    is the framework's own composer install at the package root.
$frameworkAutoload = __DIR__ . '/../vendor/autoload.php';
if (file_exists($frameworkAutoload)) {
    require $frameworkAutoload;
} else {
    fwrite(STDERR, "Boot: framework autoload missing at {$frameworkAutoload}\n");
    fwrite(STDERR, "      run `composer install` in the framework root, or rebuild the image.\n");
    exit(1);
}

// 2. App autoload. Optional — the framework boots without it (the host
//    app's classes just won't load, which means Bootstrap::register()
//    will throw immediately, surfacing a clear error).
$appAutoload = "{$appDir}/vendor/autoload.php";
if (file_exists($appAutoload)) {
    require $appAutoload;
} else {
    // Fallback for the legacy gooabb layout where vendor lives under lib/.
    $legacy = "{$appDir}/lib/vendor/autoload.php";
    if (file_exists($legacy)) {
        require $legacy;
    } else {
        fwrite(STDERR, "Boot: warning — no app autoload found near {$appDir}\n");
        fwrite(STDERR, "      App\\ classes will not resolve. Run `composer install` in the app dir.\n");
    }
}

\Nour\Server\Boot::run($appDir);
